	if (!campanhaAnterior) continue;

	const a = campanhaAtual.metrics;
	const b = campanhaAnterior.metrics;

    totalAtual.investimento += Number(a.costMicros) / 1e6;
    totalAtual.impressoes += Number(a.impressions);
    totalAtual.cliques += Number(a.clicks);
    totalAtual.conversoes += Number(a.conversions);
    totalAtual.todas_conversoes += Number(a.allConversions);
