		fim: subtrairDias(periodo.end_date, dias),

		investimento: totalAnterior.investimento,
		impressoes: totalAnterior.impressoes,
		cliques: totalAnterior.cliques,

		ctr: totalAnterior.impressoes
			? totalAnterior.cliques / totalAnterior.impressoes * 100
			: 0,

		cpc: totalAnterior.cliques
			? totalAnterior.investimento / totalAnterior.cliques
			: 0,

		cpm: totalAnterior.impressoes
			? totalAnterior.investimento / totalAnterior.impressoes * 1000
			: 0,

		conversoes: totalAnterior.conversoes,
		todas_conversoes: totalAnterior.todas_conversoes,
		valor_conversoes: totalAnterior.valor_conversoes,
		valor_todas_conversoes: totalAnterior.valor_todas_conversoes

	},

	comparativo: {

