			icone: direcao(totalAtual.impressoes, totalAnterior.impressoes)
		},

		cliques: {
			variacao: variacao(totalAtual.cliques, totalAnterior.cliques),
			icone: direcao(totalAtual.cliques, totalAnterior.cliques)
