const periodo = $('start end 2').item.json;
const dias = Number(periodo.dias);

function subtrairDias(data, qtdDias) {
  const d = new Date(data);
  d.setDate(d.getDate() - qtdDias);

  return d.toISOString().slice(0, 10);
}

const [atualResp, anteriorResp, mesResp] = $input.all().map(i => i.json);

const atual = atualResp.results;
const anterior = anteriorResp.results;

const investimentoMes = Number(mesResp.cost || 0);

function variacao(atual, anterior) {
	atual = Number(atual);
	anterior = Number(anterior);

	if (!isFinite(atual) || !isFinite(anterior) || anterior === 0) {
		return null;
	}

	return ((atual - anterior) / anterior) * 100;
}

function direcao(atual, anterior, menorMelhor = false, tolerancia = 0) {

	atual = Number(atual);
	anterior = Number(anterior);

	if (!isFinite(atual) || !isFinite(anterior)) {
		return "➖";
	}

	const dif = atual - anterior;

	if (Math.abs(dif) <= tolerancia) {
		return "➖";
	}

	if (menorMelhor) {
		return dif < 0 ? "⬆️" : "⬇️";
	}

	return dif > 0 ? "⬆️" : "⬇️";
}

const campanhasAnteriores = {};

for (const campanha of anterior) {
	campanhasAnteriores[campanha.campaign.id] = campanha;
